#include<bits/stdc++.h>
using namespace std;
int n;
constexpr double pi=acos(-1.0);
struct node
{
    double x,y;
    bool operator<(const node&b)const
    {
        return x<b.x;
    }
}a[200010];
double dist(node a,node b)
{
    return sqrt(pow(b.x-a.x,2)+pow(b.y-a.y,2));
}
double ans=1e17;
void solve(double p)
{
    p=p/180.0*pi;
    for(int i=1;i<=n;i++)
    {
        double x=a[i].x,y=a[i].y;
        double xx=x*cos(p)-y*sin(p);
        double yy=x*sin(p)+y*cos(p);
        a[i].x=xx;
        a[i].y=yy;
    }
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        for(int j=i+1;j<=min(i+5,n);j++)
        {
            ans=min(ans,dist(a[i],a[j]));
        }
    }
}
int main()
{
    srand(time(0));
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%lf%lf",&a[i].x,&a[i].y);
    }
    solve(0);
    solve(114);
    solve(rand()%360);
    solve(rand()%360);
    printf("%.4lf",ans);
    return 0;
}
